#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

/*
 * VM Memory Isolation Simulation
 * Demonstrates how hypervisors maintain memory isolation between VMs
 * This is a simplified simulation of hypervisor-level memory management
 */

#define MAX_VMS 4
#define PAGE_SIZE 4096
#define MEMORY_PAGES 256

typedef struct {
 int vm_id;
 char tenant_id[32];
 void* allocated_pages[MEMORY_PAGES];
 int page_count;
 bool is_encrypted;
} VMContext;

typedef struct {
 int page_number;
 int owner_vm_id;
 bool is_allocated;
 bool is_dirty;
} MemoryPageTable;

// Simulated physical memory (simplified)
static MemoryPageTable physical_memory[MEMORY_PAGES];
static VMContext vms[MAX_VMS];
static int vm_count = 0;

// Initialize memory page table
void init_memory_manager() {
 printf("[Hypervisor] Initializing memory manager...\n");
 for (int i = 0; i < MEMORY_PAGES; i++) {
 physical_memory[i].page_number = i;
 physical_memory[i].owner_vm_id = -1;
 physical_memory[i].is_allocated = false;
 physical_memory[i].is_dirty = false;
 }
 printf("[Hypervisor] Memory manager initialized with %d pages\n", MEMORY_PAGES);
}

// Create a new VM context
int create_vm(const char* tenant_id, bool encrypt) {
 if (vm_count >= MAX_VMS) {
 printf("[Error] Maximum VM limit reached\n");
 return -1;
 }

 VMContext* vm = &vms[vm_count];
 vm->vm_id = vm_count;
 strncpy(vm->tenant_id, tenant_id, 31);
 vm->page_count = 0;
 vm->is_encrypted = encrypt;

 printf("[Hypervisor] Created VM-%d for tenant: %s (encryption: %s)\n",
 vm->vm_id, tenant_id, encrypt ? "enabled" : "disabled");

 return vm_count++;
}

// Allocate memory for a VM (simulates hypervisor memory assignment)
void* allocate_vm_memory(int vm_id, size_t size) {
 if (vm_id < 0 || vm_id >= vm_count) {
 printf("[Error] Invalid VM ID\n");
 return NULL;
 }

 int pages_needed = (size + PAGE_SIZE - 1) / PAGE_SIZE;
 VMContext* vm = &vms[vm_id];

 printf("[Hypervisor] Allocating %zu bytes (%d pages) for VM-%d\n",
 size, pages_needed, vm_id);

 // Find free pages and allocate to this VM
 int allocated = 0;
 for (int i = 0; i < MEMORY_PAGES && allocated < pages_needed; i++) {
 if (!physical_memory[i].is_allocated) {
 physical_memory[i].is_allocated = true;
 physical_memory[i].owner_vm_id = vm_id;
 vm->allocated_pages[vm->page_count++] = &physical_memory[i];
 allocated++;
 }
 }

 if (allocated < pages_needed) {
 printf("[Error] Out of memory\n");
 return NULL;
 }

 printf("[Hypervisor] Successfully allocated %d pages to VM-%d\n",
 allocated, vm_id);
 return vm->allocated_pages[0];
}

// Verify memory isolation between VMs
bool verify_memory_isolation(int vm_id_a, int vm_id_b) {
 printf("\n[Security] Verifying memory isolation between VM-%d and VM-%d\n",
 vm_id_a, vm_id_b);

 VMContext* vm_a = &vms[vm_id_a];
 VMContext* vm_b = &vms[vm_id_b];

 // Check if any page from VM-A is accessible by VM-B
 for (int i = 0; i < vm_a->page_count; i++) {
 MemoryPageTable* page = (MemoryPageTable*)vm_a->allocated_pages[i];
 if (page->owner_vm_id == vm_id_b) {
 printf("[ALERT] ISOLATION BREACH: VM-%d page found in VM-%d's space!\n",
 vm_id_a, vm_id_b);
 return false;
 }
 }

 printf("[Security] Memory isolation VERIFIED: No cross-access detected\n");
 return true;
}

// Simulate VM escape attempt
void simulate_vm_escape_attempt(int attacker_vm_id, int target_vm_id) {
 printf("\n[SECURITY SIMULATION] VM Escape Attempt\n");
 printf(" Attacker: VM-%d (tenant: %s)\n", attacker_vm_id, vms[attacker_vm_id].tenant_id);
 printf(" Target: VM-%d (tenant: %s)\n", target_vm_id, vms[target_vm_id].tenant_id);

 // Attempt to access another VM's memory
 VMContext* attacker = &vms[attacker_vm_id];

 for (int i = 0; i < vms[target_vm_id].page_count; i++) {
 MemoryPageTable* target_page = (MemoryPageTable*)vms[target_vm_id].allocated_pages[i];

 // Check if attacker can read target's memory
 bool can_read = false; // Should always be false with proper isolation

 if (target_page->owner_vm_id == attacker_vm_id) {
 can_read = true; // This would be a breach!
 }

 if (can_read) {
 printf("[ALERT] VICTORY FOR ATTACKER - VM ESCAPE SUCCESSFUL!\n");
 printf("[ALERT] Attacker gained access to target memory at page %d\n",
 target_page->page_number);
 return;
 }
 }

 printf("[BLOCKED] VM Escape Attempt Blocked by Hypervisor\n");
 printf("[PROTECTION] Memory isolation prevented cross-VM access\n");
}

// Demonstrate live migration security
void demonstrate_migration_security(int vm_id, bool encrypt_migration) {
 printf("\n[Migration] VM-%d migration %s\n", 
 vm_id, encrypt_migration ? "with TLS encryption" : "WITHOUT ENCRYPTION");

 if (!encrypt_migration) {
 printf("[WARNING] Unencrypted migration exposes memory contents!\n");
 printf("[WARNING] Attacker on migration network can read:\n");
 printf(" - Session tokens\n");
 printf(" - Encryption keys in memory\n");
 printf(" - Application data\n");
 } else {
 printf("[SECURE] Migration traffic is encrypted with TLS 1.3\n");
 printf("[SECURE] Memory contents protected during transfer\n");
 }
}

int main() {
 printf("===========================================\n");
 printf(" VM Memory Isolation Simulation\n");
 printf("===========================================\n\n");

 // Initialize hypervisor memory manager
 init_memory_manager();

 // Create VMs for different tenants
 int vm_production = create_vm("tenant-production", true);
 int vm_development = create_vm("tenant-development", false);
 int vm_attacker = create_vm("malicious-tenant", false);

 // Allocate memory to VMs
 allocate_vm_memory(vm_production, 8192); // 2 pages
 allocate_vm_memory(vm_development, 4096); // 1 page
 allocate_vm_memory(vm_attacker, 4096); // 1 page

 // Verify isolation between production and development
 verify_memory_isolation(vm_production, vm_development);

 // Simulate VM escape attack
 simulate_vm_escape_attempt(vm_attacker, vm_production);

 // Demonstrate migration security
 demonstrate_migration_security(vm_production, true);
 demonstrate_migration_security(vm_development, false);

 printf("\n===========================================\n");
 printf(" Simulation Complete\n");
 printf("===========================================\n");

 return 0;
}

package com.cloud.vmsecurity;

import java.util.*;
import java.util.concurrent.*;

/**
 * VM Security Policy Manager
 * Implements micro-segmentation and security policy enforcement
 * for virtual machine infrastructure
 */

// Security policy types
enum PolicyType {
 NETWORK_ACCESS,
 RESOURCE_LIMIT,
 ENCRYPTION_REQUIRED,
 SNAPSHOT_RETENTION,
 LIVE_MIGRATION_SECURITY
}

enum PolicyAction {
 ALLOW,
 DENY,
 AUDIT,
 ALERT
}

// Security policy definition
class SecurityPolicy {
 private final String policyId;
 private final PolicyType type;
 private final String sourceVm;
 private final String destinationVm;
 private final PolicyAction action;
 private final Map<String, Object> conditions;

 public SecurityPolicy(String policyId, PolicyType type, String sourceVm, 
 String destinationVm, PolicyAction action) {
 this.policyId = policyId;
 this.type = type;
 this.sourceVm = sourceVm;
 this.destinationVm = destinationVm;
 this.action = action;
 this.conditions = new HashMap<>();
 }

 // Getters
 public String getPolicyId() { return policyId; }
 public PolicyType getType() { return type; }
 public String getSourceVm() { return sourceVm; }
 public String getDestinationVm() { return destinationVm; }
 public PolicyAction getAction() { return action; }
 public void addCondition(String key, Object value) { conditions.put(key, value); }
 public Object getCondition(String key) { return conditions.get(key); }
}

// VM metadata
class VMMetadata {
 private final String vmId;
 private final String tenantId;
 private final String vlanId;
 private final String securityGroup;
 private boolean encryptionEnabled;
 private int maxCpuPercent;
 private int maxMemoryMB;

 public VMMetadata(String vmId, String tenantId, String vlanId, String securityGroup) {
 this.vmId = vmId;
 this.tenantId = tenantId;
 this.vlanId = vlanId;
 this.securityGroup = securityGroup;
 this.encryptionEnabled = false;
 this.maxCpuPercent = 100;
 this.maxMemoryMB = 65536;
 }

 // Getters and setters
 public String getVmId() { return vmId; }
 public String getTenantId() { return tenantId; }
 public String getVlanId() { return vlanId; }
 public String getSecurityGroup() { return securityGroup; }
 public boolean isEncryptionEnabled() { return encryptionEnabled; }
 public void setEncryptionEnabled(boolean enabled) { this.encryptionEnabled = enabled; }
 public int getMaxCpuPercent() { return maxCpuPercent; }
 public void setMaxCpuPercent(int max) { this.maxCpuPercent = max; }
 public int getMaxMemoryMB() { return maxMemoryMB; }
 public void setMaxMemoryMB(int max) { this.maxMemoryMB = max; }
}

// Security audit log entry
class SecurityAuditLog {
 private final long timestamp;
 private final String eventType;
 private final String sourceVm;
 private final String destinationVm;
 private final PolicyAction action;
 private final boolean allowed;
 private final String reason;

 public SecurityAuditLog(String eventType, String sourceVm, String destinationVm,
 PolicyAction action, boolean allowed, String reason) {
 this.timestamp = System.currentTimeMillis();
 this.eventType = eventType;
 this.sourceVm = sourceVm;
 this.destinationVm = destinationVm;
 this.action = action;
 this.allowed = allowed;
 this.reason = reason;
 }

 @Override
 public String toString() {
 return String.format("[%d] %s: %s -> %s | Action: %s | %s | Reason: %s",
 timestamp, eventType, sourceVm, destinationVm, action, 
 allowed ? "ALLOWED" : "DENIED", reason);
 }
}

/**
 * Micro-segmentation and Security Policy Engine
 */
public class VMSecurityPolicyManager {

 private final Map<String, VMMetadata> vmRegistry;
 private final List<SecurityPolicy> policies;
 private final ConcurrentLinkedQueue<SecurityAuditLog> auditLogs;
 private final Map<String, Integer> resourceUsage;

 public VMSecurityPolicyManager() {
 this.vmRegistry = new ConcurrentHashMap<>();
 this.policies = new CopyOnWriteArrayList<>();
 this.auditLogs = new ConcurrentLinkedQueue<>();
 this.resourceUsage = new ConcurrentHashMap<>();
 }

 // Register a VM in the security manager
 public void registerVM(VMMetadata vm) {
 vmRegistry.put(vm.getVmId(), vm);
 resourceUsage.put(vm.getVmId(), 0);
 System.out.println("[Security] Registered VM: " + vm.getVmId() + 
 " (Tenant: " + vm.getTenantId() + 
 ", VLAN: " + vm.getVlanId() + ")");
 }

 // Add a security policy
 public void addPolicy(SecurityPolicy policy) {
 policies.add(policy);
 System.out.println("[Security] Policy added: " + policy.getPolicyId() + 
 " - " + policy.getType());
 }

 // Evaluate if VM-to-VM communication is allowed (micro-segmentation)
 public boolean evaluateNetworkAccess(String sourceVmId, String destinationVmId) {
 VMMetadata source = vmRegistry.get(sourceVmId);
 VMMetadata dest = vmRegistry.get(destinationVmId);

 if (source == null || dest == null) {
 logAudit("NETWORK_ACCESS", sourceVmId, destinationVmId, 
 PolicyAction.DENY, false, "VM not found");
 return false;
 }

 // Cross-tenant isolation: different tenants cannot communicate by default
 if (!source.getTenantId().equals(dest.getTenantId())) {
 logAudit("NETWORK_ACCESS", sourceVmId, destinationVmId, 
 PolicyAction.DENY, false, "Cross-tenant isolation");
 System.out.println("[BLOCKED] Cross-tenant communication: " + 
 source.getTenantId() + " -> " + dest.getTenantId());
 return false;
 }

 // Check security group policies
 if (!source.getSecurityGroup().equals(dest.getSecurityGroup())) {
 // Different security groups - check if policy allows
 boolean allowed = hasInterGroupPolicy(source.getSecurityGroup(), 
 dest.getSecurityGroup());
 if (!allowed) {
 logAudit("NETWORK_ACCESS", sourceVmId, destinationVmId, 
 PolicyAction.DENY, false, "Different security groups");
 return false;
 }
 }

 logAudit("NETWORK_ACCESS", sourceVmId, destinationVmId, 
 PolicyAction.ALLOW, true, "Micro-segmentation policy satisfied");
 return true;
 }

 // Check inter-security-group policy
 private boolean hasInterGroupPolicy(String srcGroup, String destGroup) {
 for (SecurityPolicy p : policies) {
 if (p.getType() == PolicyType.NETWORK_ACCESS &&
 p.getSourceVm().equals(srcGroup) &&
 p.getDestinationVm().equals(destGroup) &&
 p.getAction() == PolicyAction.ALLOW) {
 return true;
 }
 }
 return false;
 }

 // Evaluate resource allocation (prevent DoS)
 public boolean evaluateResourceAllocation(String vmId, int requestedCpu, 
 int requestedMemoryMB) {
 VMMetadata vm = vmRegistry.get(vmId);

 if (vm == null) {
 return false;
 }

 // Check CPU limit
 int cpuLimit = vm.getMaxCpuPercent();
 if (requestedCpu > cpuLimit) {
 logAudit("RESOURCE_ALLOC", vmId, "HYPERVISOR", 
 PolicyAction.DENY, false, "CPU limit exceeded");
 System.out.println("[BLOCKED] VM-" + vmId + " CPU request exceeds limit");
 return false;
 }

 // Check memory limit
 if (requestedMemoryMB > vm.getMaxMemoryMB()) {
 logAudit("RESOURCE_ALLOC", vmId, "HYPERVISOR", 
 PolicyAction.DENY, false, "Memory limit exceeded");
 System.out.println("[BLOCKED] VM-" + vmId + " Memory request exceeds limit");
 return false;
 }

 logAudit("RESOURCE_ALLOC", vmId, "HYPERVISOR", 
 PolicyAction.ALLOW, true, "Resource within limits");
 return true;
 }

 // Evaluate live migration security
 public boolean evaluateLiveMigration(String vmId, String destinationHost) {
 VMMetadata vm = vmRegistry.get(vmId);

 if (vm == null) {
 return false;
 }

 // Check encryption requirement for migration
 if (!vm.isEncryptionEnabled()) {
 logAudit("LIVE_MIGRATION", vmId, destinationHost, 
 PolicyAction.DENY, false, "VM encryption not enabled");
 System.out.println("[BLOCKED] VM-" + vmId + " cannot migrate: encryption disabled");
 return false;
 }

 logAudit("LIVE_MIGRATION", vmId, destinationHost, 
 PolicyAction.ALLOW, true, "Migration with encryption approved");
 return true;
 }

 // Evaluate snapshot creation
 public boolean evaluateSnapshot(String vmId, int existingSnapshots) {
 for (SecurityPolicy p : policies) {
 if (p.getType() == PolicyType.SNAPSHOT_RETENTION) {
 int maxSnapshots = (int) p.getCondition("max_snapshots");
 if (existingSnapshots >= maxSnapshots) {
 logAudit("SNAPSHOT_CREATE", vmId, "STORAGE", 
 PolicyAction.DENY, false, "Max snapshots exceeded");
 return false;
 }
 }
 }
 return true;
 }

 // Log security audit event
 private void logAudit(String eventType, String sourceVm, String destVm,
 PolicyAction action, boolean allowed, String reason) {
 SecurityAuditLog log = new SecurityAuditLog(
 eventType, sourceVm, destVm, action, allowed, reason);
 auditLogs.add(log);
 }

 // Print audit logs
 public void printAuditLogs() {
 System.out.println("\n========== SECURITY AUDIT LOGS ==========");
 for (SecurityAuditLog log : auditLogs) {
 System.out.println(log);
 }
 System.out.println("==========================================\n");
 }

 // Main demonstration
 public static void main(String[] args) {
 VMSecurityPolicyManager securityManager = new VMSecurityPolicyManager();

 System.out.println("=== VM Security Policy Manager Demo ===\n");

 // Register VMs for different tenants
 VMMetadata prodWeb = new VMMetadata("vm-web-prod", "tenant-a", "vlan-10", "web-sg");
 prodWeb.setEncryptionEnabled(true);
 securityManager.registerVM(prodWeb);

 VMMetadata prodDb = new VMMetadata("vm-db-prod", "tenant-a", "vlan-20", "db-sg");
 prodDb.setEncryptionEnabled(true);
 securityManager.registerVM(prodDb);

 VMMetadata devVm = new VMMetadata("vm-dev", "tenant-b", "vlan-30", "dev-sg");
 devVm.setEncryptionEnabled(false);
 securityManager.registerVM(devVm);

 // Add micro-segmentation policies
 SecurityPolicy webToDb = new SecurityPolicy("pol-001", PolicyType.NETWORK_ACCESS, 
 "web-sg", "db-sg", PolicyAction.ALLOW);
 securityManager.addPolicy(webToDb);

 // Test 1: Same tenant, same security group
 System.out.println("\n--- Test 1: Intra-tenant communication ---");
 securityManager.evaluateNetworkAccess("vm-web-prod", "vm-db-prod");

 // Test 2: Cross-tenant (should be blocked)
 System.out.println("\n--- Test 2: Cross-tenant communication (should block) ---");
 securityManager.evaluateNetworkAccess("vm-web-prod", "vm-dev");

 // Test 3: Resource limit enforcement
 System.out.println("\n--- Test 3: Resource allocation check ---");
 securityManager.evaluateResourceAllocation("vm-web-prod", 50, 8192);
 securityManager.evaluateResourceAllocation("vm-web-prod", 150, 8192); // Exceeds limit

 // Test 4: Live migration security
 System.out.println("\n--- Test 4: Live migration security ---");
 securityManager.evaluateLiveMigration("vm-web-prod", "host-2");
 securityManager.evaluateLiveMigration("vm-dev", "host-2"); // Should fail

 // Test 5: Snapshot retention
 System.out.println("\n--- Test 5: Snapshot policy ---");
 SecurityPolicy snapshotPolicy = new SecurityPolicy("pol-002", 
 PolicyType.SNAPSHOT_RETENTION, "*", "*", PolicyAction.ALLOW);
 snapshotPolicy.addCondition("max_snapshots", 3);
 securityManager.addPolicy(snapshotPolicy);
 System.out.println("Create snapshot allowed: " + securityManager.evaluateSnapshot("vm-web-prod", 2));
 System.out.println("Create snapshot allowed: " + securityManager.evaluateSnapshot("vm-web-prod", 4));

 // Print all audit logs
 securityManager.printAuditLogs();
 }
}
